# Function to create an empty board
def create_board(size):
    return [['.' for _ in range(size)] for _ in range(size)]

# Function to initialize the board with pieces
def init_board(positions):
    board = create_board(BOARD_SIZE)
    for (x, y), piece in positions.items():
        board[x][y] = piece
    return board

# Function to print the board
def print_board(board):
    for row in board:
        print(' '.join(row))

# Function to check if a move is valid
def is_valid_move(board, player, start_x, start_y, end_x, end_y):
    # Check if the start and end positions are on the board
    if not (0 <= start_x < BOARD_SIZE and 0 <= start_y < BOARD_SIZE and 0 <= end_x < BOARD_SIZE and 0 <= end_y < BOARD_SIZE):
        return False
    # Check if the starting position contains a piece of the current player
    if board[start_x][start_y] != player:
        return False
    # Calculate the move direction
    dx, dy = end_x - start_x, end_y - start_y
    # Check if the move is diagonal and one step
    if abs(dx) == 1 and abs(dy) == 1:
        return True
    # Check for capture moves
    if abs(dx) == 2 and abs(dy) == 2 and board[end_x][end_y] == '.':
        mid_x, mid_y = (start_x + end_x) // 2, (start_y + end_y) // 2
        return board[mid_x][mid_y] != '.' and board[mid_x][mid_y].lower() != player.lower()
    return False

# Function to apply a move to the board
def apply_move(board, player, start_x, start_y, end_x, end_y):
    if not is_valid_move(board, player, start_x, start_y, end_x, end_y):
        raise ValueError('Invalid move')
    dx, dy = end_x - start_x, end_y - start_y
    board[start_x][start_y] = '.'
    board[end_x][end_y] = player
    # Check for and handle captures
    if abs(dx) == 2 and abs(dy) == 2:
        mid_x, mid_y = (start_x + end_x) // 2, (start_y + end_y) // 2
        board[mid_x][mid_y] = '.'
    # Check for kinging
    if player == 'b' and end_x == BOARD_SIZE - 1 or player == 'r' and end_x == 0:
        board[end_x][end_y] = player.upper()
    return board

# Function to get all valid moves for a player
def get_valid_moves(board, player):
    valid_moves = []
    for x in range(BOARD_SIZE):
        for y in range(BOARD_SIZE):
            if board[x][y].lower() == player.lower():
                for dx, dy in MOVES[player]:
                    end_x, end_y = x + dx, y + dy
                    try:
                        apply_move(board, player, x, y, end_x, end_y)
                        valid_moves.append((x, y, end_x, end_y))
                        board[x][y] = player.lower()
                    except ValueError:
                        continue
    return valid_moves

# Function to check if the game is over
def is_game_over(board):
    black_pieces = sum(row.count('b') for row in board)
    red_pieces = sum(row.count('r') for row in board)
    if black_pieces == 0 or red_pieces == 0:
        return True
    return False

# Main game loop
def main():
    board = init_board(INITIAL_POSITION)
    current_player = 'b'
    while not is_game_over(board):
        print_board(board)
        try:
            start_x, start_y = map(int, input(f'Player {current_player.upper()}, enter your move (from-x from-y to-x to-y): ').split())
            end_x, end_y = map(int, input('to-x to-y: ').split())
            apply_move(board, current_player, start_x, start_y, end_x, end_y)
        except ValueError as e:
            print(e)
        else:
            if len(get_valid_moves(board, current_player)) == 0:
                print(f'Player {current_player.upper()} has no valid moves and loses.')
                break
            current_player = 'r' if current_player == 'b' else 'b'
    print_board(board)
    print('Game over!')

if __name__ == '__main__':
    main()"
